/**
 * Sender-residency sanctioned gate (OFAC E.O. 13466 — DPRK, 31 CFR Part 510).
 *
 * Scenario #15 of guides/use-cases.md: an AccountHolder whose primary
 * residential address is in an OFAC comprehensive-sanctioned country
 * may not originate any transaction, regardless of counterparty.
 * The set covers the comprehensive-program subjects (DPRK, Iran,
 * Cuba, Syria) — not the partial-program subjects (e.g. Crimea
 * region within RU), which scenarios #14 and #16 handle separately.
 *
 * Reads `debtor_payment_account.account_holder.legal_entity.country_of_residence`,
 * a flat ISO 3166-1 alpha-2 code that `AtomicFi.RuleEngine.Payload`
 * projects from the LE's primary residential address (falling back
 * to citizenship_country when no address is loaded).
 *
 * When the resolved code is in the sanctioned set, emits a blocked
 * Control per LedgerAccount on the debtor side. cap=0 +
 * is_blocked=true converts to status='rejected' with
 * rejected_rule='ah_country_kp_residence' at limits-at-entry time.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const ah = debtor.account_holder;
  const le = ah && ah.legal_entity;
  const country = le && le.country_of_residence;
  if (!country) return { ledger_accounts: {} };

  const sanctioned = ['KP', 'IR', 'CU', 'SY'];
  if (sanctioned.indexOf(country) === -1) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'ah_country_kp_residence',
      block_reason: 'ah_country_kp_residence',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
